package com.openclaw;import org.mybatis.spring.annotation.MapperScan;import org.springframework.boot.SpringApplication;import org.springframework.boot.autoconfigure.SpringBootApplication;/** * 项目启动入口。 * 设计说明： * 1. 使用 @SpringBootApplication 作为统一自动装配入口，符合大厂项目主应用规范。 * 2. 使用 @MapperScan 扫描 MyBatis-Plus Mapper，避免每个 Mapper 单独加 @Mapper。 */@SpringBootApplication@MapperScan("com.openclaw.mapper")public class OpenClawJavaApplication {    public static void main(String[] args) {        SpringApplication.run(OpenClawJavaApplication.class, args);    }}